hrink: 0;\n}\n\n.wb-section {\n  font-size: 11px;\n  font-weight: 700;\n  color: var(--ide-dim-3);\n  text-transform: uppercase;\n  letter-spacing: 0.8px;\n  padding-top: 6px;\n  border-top: 1px solid var(--ide-border-soft);\n  margin-top: 2px;\n}\n\n.wb-select {\n  flex: 1;\n  background: var(--ide-input-bg);\n  border: 1px solid var(--ide-input-border);\n  border-radius: 4px;\n  color: var(--ide-text);\n  font-size: 12px;\n  padding: 4px 6px;\n  outline: none;\n}\n\n.wb-select:focus { border-color: var(--ide-accent-border); }\n\n.wb-select option {\n  background: var(--ide-bg2);\n  color: var(--ide-text);\n}\n\n.wb-input {\n  flex: 1;\n  background: var(--ide-input-bg);\n  border: 1px solid var(--ide-input-border);\n  border-radius: 4px;\n  color: var(--ide-text);\n  font-size: 12px;\n  padding: 4px 8px;\n  outline: none;\n}\n\n.wb-input:focus { border-color: var(--ide-accent-border); }\n.wb-input::placeholder { color: var(--ide-dim-3); }\n.wb-input-num { max-width: 80px; }\n\n.wb-toggle {\n  display: flex;\n  align-items: center;\n  gap: 6px;\n  font-size: 12px;\n  color: var(--ide-dim);\n  cursor: pointer;\n}\n\n.wb-toggle input[type='checkbox'] {\n  width: 14px;\n  height: 14px;\n  accent-color: var(--ide-accent);\n  cursor: pointer;\n}\n</style>\n"],"sourceRoot":""}]);
